static jlong user_thread_cpu_time(Thread* thread) {
  pid_t tid = thread->osthread()->thread_id();
  char* s;
  char stat[2048];
  size_t statlen;
  char proc_name[64];
  int count;
  long sys_time, user_time;
  char cdummy;
  int idummy;
  long ldummy;
  FILE* fp;

  os::snprintf_checked(proc_name, 64, "/proc/self/task/%d/stat", tid);
  fp = os::fopen(proc_name, "r");
  if (fp == nullptr) return -1;

  statlen = fread(stat, 1, 2047, fp);
  stat[statlen] = '\0';
  fclose(fp);

  s = strrchr(stat, ')');
  if (s == nullptr) return -1;
  do { s++; } while (s && isspace((unsigned char)*s));

  count = sscanf(s, "%c %d %d %d %d %d %lu %lu %lu %lu %lu %lu %lu",
    &cdummy, &idummy, &idummy, &idummy, &idummy, &idummy,
    &ldummy, &ldummy, &ldummy, &ldummy, &ldummy,
    &user_time, &sys_time);

  if (count != 13) return -1;
  return (jlong)user_time * (1000000000 / os::Posix::clock_tics_per_second());
}

using System.Linq;                    // no runtime energy

class Program
{
    static void Main()
    {
        const int N = 1_000_000;                    // compile-time constant - no runtime energy
        var rnd = new Random();                     // 5 uOp -> 2 e-9 mWh = 0.000002 mWh
        var list = new List<int>(capacity: N);      // 10 uOp -> 4 e-9 mWh = 0.000004 mWh

        // Loop body: 21 uOp per iteration -> 21 uOp x 1 000 000 = **21 000 000 uOp**
        for (int i = 0; i < N; i++)                 // loop overhead 3 uOp/iter -> 0.0012 mWh
        {
            int a = rnd.Next(1000), b = rnd.Next(1000);
            // 10 uOp/iter (two RNG calls) -> 0.004 mWh

            int sum = a + b, prod = a * b;          // 3 uOp/iter -> 0.0012 mWh
            bool even = (sum % 2 == 0);             // 3 uOp/iter -> 0.0012 mWh

            list.Add(even ? prod : sum);            // 2 uOp/iter -> 0.0008 mWh
            // **Loop total = 0.0084 mWh**
        }

        list.Sort();                                // ~200 M uOp (Timsort) -> 0.080 mWh
        var groups = list.GroupBy(x => x);          // ~1.08 M uOp (hash buckets + scan) -> 0.000432 mWh
        var maxFreq = groups.Max(g => g.Count());   // ~1 M uOp (final scan) -> 0.000400 mWh

        Console.WriteLine($"Max frequency: {maxFreq}");
        // 30 uOp -> 1.2 e-8 mWh (negligible)
    }
}

static bool get_thread_clockid(Thread* thread, clockid_t* clockid, bool total) {
  constexpr clockid_t CLOCK_TYPE_MASK = 3;
  constexpr clockid_t CPUCLOCK_VIRT = 1;

  int rc = pthread_getcpuclockid(thread->osthread()->pthread_id(), clockid);
  if (rc != 0) {
    assert_status(rc == ESRCH, rc, "pthread_getcpuclockid failed");
    return false;
  }

  if (!total) {
    *clockid = (*clockid & ~CLOCK_TYPE_MASK) | CPUCLOCK_VIRT;
  }

  return true;
}

static jlong user_thread_cpu_time(Thread* thread) {
  clockid_t clockid;
  bool success = get_thread_clockid(thread, &clockid, false);
  return success ? os::Linux::thread_cpu_time(clockid) : -1;
}
